// mm/src/store/workflowContext.js
import React, { createContext, useContext, useMemo, useState } from 'react';

const WorkflowContext = createContext(null);

export const WorkflowProvider = ({ children }) => {
  /**
   * Upload phases:
   *  - select: initial upload dropzone
   *  - ready:  after at least one file uploaded (shows "Start AI Analysis")
   *  - metadata: Basic Information + Organize Your Files screen
   */
  const [uploadPhase, setUploadPhase] = useState('select');

  // Book details collected in upload metadata step
  const [bookDetails, setBookDetails] = useState({
    title: '',
    author: '',
    category: '',
    subcategory: '',
  });

  // Manuscript file list (metadata + file object for preview extraction)
  const [manuscriptFiles, setManuscriptFiles] = useState([]);

  // Design choices (mini-wizard inside Design step)
  const [design, setDesign] = useState({
    analyzed: false,
    stage: 'typography', // typography -> layout -> trim -> summary
    typography: null, // e.g. 'serif' | 'sans' | 'hybrid' etc
    layout: null, // e.g. 'standard' | 'spacious' | 'compact'
    trim: null, // e.g. '5.5x8.5' | '5x8' | '6x9'
  });

  // Details step form state (Step 4)
  const [details, setDetails] = useState({
    // Author Information
    prefix: '',
    firstName: '',
    middleName: '',
    lastName: '',
    suffix: '',
    contributors: [],

    // Book Information
    subtitle: '',
    description: '',
    primaryLanguage: 'English',

    // Target Audience
    ageRange: 'All Ages',
    demographics: [],
    marketPositioning: '',

    // Publishing Goals
    distributionChannels: ['Amazon KDP'],
    publishingTimeline: '',
    authorExperienceLevel: '',

    // Additional Info
    seriesInformation: '',
    brandingPreferences: '',
    marketingObjectives: '',
  });

  // --- helpers ---
  // Upsert a file (replace by id if exists; otherwise add)
  const upsertFile = (fileMeta) => {
    if (!fileMeta?.id) return;

    setManuscriptFiles((prev) => {
      const idx = prev.findIndex((f) => f.id === fileMeta.id);
      if (idx === -1) return [...prev, fileMeta];

      const next = [...prev];
      next[idx] = { ...next[idx], ...fileMeta };
      return next;
    });
  };

  const removeFile = (id) => {
    setManuscriptFiles((prev) => prev.filter((f) => f.id !== id));
  };

  const resetWorkflow = () => {
    setUploadPhase('select');
    setBookDetails({ title: '', author: '', category: '', subcategory: '' });
    setManuscriptFiles([]);
    setDesign({
      analyzed: false,
      stage: 'typography',
      typography: null,
      layout: null,
      trim: null,
    });
    setDetails({
      prefix: '',
      firstName: '',
      middleName: '',
      lastName: '',
      suffix: '',
      contributors: [],
      subtitle: '',
      description: '',
      primaryLanguage: 'English',
      ageRange: 'All Ages',
      demographics: [],
      marketPositioning: '',
      distributionChannels: ['Amazon KDP'],
      publishingTimeline: '',
      authorExperienceLevel: '',
      seriesInformation: '',
      brandingPreferences: '',
      marketingObjectives: '',
    });
  };

  const value = useMemo(
    () => ({
      // upload state
      uploadPhase,
      setUploadPhase,

      bookDetails,
      setBookDetails,

      manuscriptFiles,
      setManuscriptFiles,
      addFile: upsertFile, // keep existing API name
      removeFile,

      // design state
      design,
      setDesign,

      // details state
      details,
      setDetails,

      // utilities
      resetWorkflow,
    }),
    [uploadPhase, bookDetails, manuscriptFiles, design, details]
  );

  return <WorkflowContext.Provider value={value}>{children}</WorkflowContext.Provider>;
};

export const useWorkflow = () => {
  const ctx = useContext(WorkflowContext);
  if (!ctx) throw new Error('useWorkflow must be used inside WorkflowProvider');
  return ctx;
};
